-- =====================================================
-- LERA Attendance Service - Seed Data
-- =====================================================
-- This file creates initial data for attendance records, teacher sessions, leaves
-- Uses PostgreSQL ON CONFLICT for upsert operations

-- =====================================================
-- TEACHER_SESSIONS (Teacher teaching sessions)
-- =====================================================
-- Idempotent: sql.init runs on every boot, so only seed when this teacher has no sessions yet
-- (ids are gen_random_uuid, so a plain re-insert would otherwise accumulate duplicates).
DO $$ BEGIN
IF NOT EXISTS (SELECT 1 FROM teacher_sessions WHERE teacher_id = 'b0000000-0000-0000-0000-000000000001') THEN
INSERT INTO teacher_sessions (id, teacher_id, class_id, session_date, start_time, end_time, duration_hours, session_type, status, students_attended, notes, created_at)
VALUES
